     1→#!/usr/bin/env node
     2→/**
     3→ * Incremental Email Fetch CLI (T042a)
     4→ *
     5→ * Wires together Gmail API integration (T037), email fetching (T038b),
     6→ * and Prisma persistence (T042) to fetch and persist new emails since
     7→ * the last recorded timestamp in the database.
     8→ *
     9→ * Usage:
    10→ *   npm run fetch:emails                    # Fetch since last DB timestamp
    11→ *   npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
    12→ */
    13→
    14→import * as fs from 'fs';
    15→import * as path from 'path';
    16→import { GmailClient, OAuth2Tokens } from '../gmail/gmail-client';
    17→import { EmailFetcher, EmailMessage } from '../gmail/email-fetcher';
    18→import { EmailRepository } from '../persistence/email-repository';
    19→import { loadEnvironment } from '../config/env';
    20→
    21→/**
    22→ * Options for fetchAndPersistEmails function
    23→ */
    24→export interface FetchAndPersistOptions {
    25→  gmailClient: GmailClient;
    26→  emailFetcher: EmailFetcher;
    27→  repository: EmailRepository;
    28→  sinceDate?: Date; // Optional: Override last DB timestamp
    29→}
    30→
    31→/**
    32→ * Error details for fetch/persist operations
    33→ */
    34→export interface FetchError {
    35→  type: 'authentication' | 'fetch' | 'persistence';
    36→  message: string;
    37→  originalError?: unknown;
    38→}
    39→
    40→/**
    41→ * Result summary for fetch and persist operation
    42→ */
    43→export interface FetchAndPersistResult {
    44→  success: boolean;
    45→  fetchedCount: number; // New messages since timestamp
    46→  persistedCount: number; // Total messages persisted (new + updated from threads)
    47→  threadsAffected: number; // Number of unique threads processed
    48→  sinceTimestamp: Date | null;
    49→  errors: FetchError[];
    50→  startTime: Date;
    51→  endTime: Date;
    52→  durationMs: number;
    53→}
    54→
    55→/**
    56→ * Fetch and persist new emails since last database timestamp
    57→ *
    58→ * This function implements the core logic for incremental email fetching:
    59→ * 1. Query last email timestamp from database (unless sinceDate provided)
    60→ * 2. Fetch new emails from Gmail API since that timestamp
    61→ * 3. Persist emails using Prisma batch upsert
    62→ * 4. Return detailed result summary with error handling
    63→ *
    64→ * @param options - Configuration for Gmail client, fetcher, and repository
    65→ * @returns Result summary with counts, timestamps, and any errors
    66→ *
    67→ * @example
    68→ * ```typescript
    69→ * const result = await fetchAndPersistEmails({
    70→ *   gmailClient: new GmailClient(auth),
    71→ *   emailFetcher: new EmailFetcher(gmailClient),
    72→ *   repository: new EmailRepository(),
    73→ * });
    74→ *
    75→ * console.log(`Fetched ${result.fetchedCount} emails, persisted ${result.persistedCount}`);
    76→ * ```
    77→ */
    78→export async function fetchAndPersistEmails(options: FetchAndPersistOptions): Promise<FetchAndPersistResult> {
    79→  const { gmailClient, emailFetcher, repository, sinceDate } = options;
    80→
    81→  const startTime = new Date();
    82→  const result: FetchAndPersistResult = {
    83→    success: false,
    84→    fetchedCount: 0,
    85→    persistedCount: 0,
    86→    threadsAffected: 0,
    87→    sinceTimestamp: null,
    88→    errors: [],
    89→    startTime,
    90→    endTime: startTime, // Will be updated at end
    91→    durationMs: 0,
    92→  };
    93→
    94→  try {
    95→    // Step 1: Check Gmail authentication
    96→    const authStatus = await gmailClient.getAuthStatus();
    97→    if (!authStatus.authenticated || !authStatus.tokenValid) {
    98→      result.errors.push({
    99→        type: 'authentication',
   100→        message: 'Gmail client is not authenticated. Please authenticate before fetching emails.',
   101→      });
   102→      return result;
   103→    }
   104→
   105→    // Step 2: Determine timestamp to fetch from
   106→    let fetchSince: Date | null = null;
   107→
   108→    if (sinceDate) {
   109→      // Use custom date if provided
   110→      fetchSince = sinceDate;
   111→      result.sinceTimestamp = sinceDate;
   112→    } else {
   113→      // Query last email timestamp from database
   114→      try {
   115→        fetchSince = await repository.getLastEmailTimestamp();
   116→        result.sinceTimestamp = fetchSince;
   117→      } catch (error) {
   118→        result.errors.push({
   119→          type: 'persistence',
   120→          message: `Failed to query last email timestamp: ${error instanceof Error ? error.message : String(error)}`,
   121→          originalError: error,
   122→        });
   123→        return result;
   124→      }
   125→    }
   126→
   127→    // Step 3: Fetch emails from Gmail API using efficient thread-based approach
   128→    let allThreadMessages: EmailMessage[];
   129→    let newMessageIds: Set<string>;
   130→
   131→    try {
   132→      if (fetchSince) {
   133→        // Step 3a: First, do lightweight list to get new message refs and their thread IDs
   134→        const year = fetchSince.getFullYear();
   135→        const month = String(fetchSince.getMonth() + 1).padStart(2, '0');
   136→        const day = String(fetchSince.getDate()).padStart(2, '0');
   137→        const dateQuery = `after:${year}/${month}/${day}`;
   138→
   139→        console.log(`Fetching messages since ${fetchSince.toISOString()}`);
   140→        console.log(`Gmail query: ${dateQuery}`);
   141→
   142→        // Use Gmail API directly to get just message IDs and thread IDs (minimal format)
   143→        // This avoids parsing issues since we don't need full email data yet
   144→        const messageRefs: Array<{ id: string; threadId: string }> = [];
   145→        let pageToken: string | undefined | null = undefined;
   146→
   147→        // Fetch all pages of message references
   148→        do {
   149→          const listResponse = await gmailClient.listMessages(
   150→            {
   151→              q: dateQuery,
   152→              pageToken: pageToken || undefined,
   153→              maxResults: 500, // Max allowed by Gmail API
   154→            },
   155→            {
   156→              retryOnRateLimit: true,
   157→              maxRetries: 3,
   158→            }
   159→          );
   160→
   161→          const messages = listResponse.messages || [];
   162→          for (const msg of messages) {
   163→            if (msg.id && msg.threadId) {
   164→              messageRefs.push({ id: msg.id, threadId: msg.threadId });
   165→            }
   166→          }
   167→
   168→          pageToken = listResponse.nextPageToken;
   169→        } while (pageToken);
   170→
   171→        if (messageRefs.length === 0) {
   172→          console.log('No new messages found');
   173→          result.success = true;
   174→          return result;
   175→        }
   176→
   177→        // Track which messages are NEW (vs updated old messages in same threads)
   178→        newMessageIds = new Set(messageRefs.map((m) => m.id));
   179→        result.fetchedCount = newMessageIds.size;
   180→
   181→        // Step 3b: Extract unique thread IDs from new messages
   182→        const uniqueThreadIds = [...new Set(messageRefs.map((m) => m.threadId))];
   183→        result.threadsAffected = uniqueThreadIds.length;
   184→
   185→        console.log(`Found ${newMessageIds.size} new messages in ${uniqueThreadIds.length} threads`);
   186→        console.log(
   187→          `Using thread-based fetching (${uniqueThreadIds.length} API calls instead of ${newMessageIds.size})`
   188→        );
   189→
   190→        // Step 3c: Fetch complete threads (gets ALL messages with current labels!)
   191→        const threadResult = await emailFetcher.fetchEmailsByThreads(uniqueThreadIds, {
   192→          format: 'full',
   193→          continueOnError: true,
   194→        });
   195→
   196→        allThreadMessages = threadResult.emails;
   197→        console.log(`Retrieved ${allThreadMessages.length} total messages (includes old messages in threads)`);
   198→      } else {
   199→        // First fetch - use traditional approach (no previous data to sync)
   200→        console.log('First fetch - fetching initial batch');
   201→        const fetchResult = await emailFetcher.fetchEmails({ maxResults: 100 });
   202→        allThreadMessages = fetchResult.emails;
   203→        newMessageIds = new Set(allThreadMessages.map((e) => e.id));
   204→        result.fetchedCount = allThreadMessages.length;
   205→        result.threadsAffected = new Set(allThreadMessages.map((e) => e.threadId)).size;
   206→      }
   207→    } catch (error) {
   208→      result.errors.push({
   209→        type: 'fetch',
   210→        message: `Failed to fetch emails from Gmail API: ${error instanceof Error ? error.message : String(error)}`,
   211→        originalError: error,
   212→      });
   213→      return result;
   214→    }
   215→
   216→    // Step 4: Persist ALL messages from fetched threads to database
   217→    // This updates labels on old messages and adds new messages!
   218→    if (allThreadMessages.length > 0) {
   219→      try {
   220→        console.log(`Persisting ${allThreadMessages.length} messages to database...`);
   221→        await repository.batchInsert(allThreadMessages);
   222→        result.persistedCount = allThreadMessages.length;
   223→        result.success = true;
   224→
   225→        const updatedCount = allThreadMessages.length - result.fetchedCount;
   226→        if (updatedCount > 0) {
   227→          console.log(`  ↳ ${result.fetchedCount} new messages, ${updatedCount} updated messages`);
   228→        }
   229→      } catch (error) {
   230→        result.errors.push({
   231→          type: 'persistence',
   232→          message: `Failed to persist emails to database: ${error instanceof Error ? error.message : String(error)}`,
   233→          originalError: error,
   234→        });
   235→        return result;
   236→      }
   237→    } else {
   238→      // No new emails, but operation was successful
   239→      result.success = true;
   240→    }
   241→
   242→    return result;
   243→  } finally {
   244→    // Update end time and duration
   245→    result.endTime = new Date();
   246→    result.durationMs = result.endTime.getTime() - result.startTime.getTime();
   247→  }
   248→}
   249→
   250→/**
   251→ * Parse command-line arguments
   252→ *
   253→ * Supports:
   254→ *   --since=YYYY-MM-DD   # Fetch emails since this date
   255→ *   --help               # Show usage information
   256→ */
   257→function parseArguments(): { sinceDate?: Date; showHelp: boolean } {
   258→  const args = process.argv.slice(2);
   259→  const result: { sinceDate?: Date; showHelp: boolean } = { showHelp: false };
   260→
   261→  for (const arg of args) {
   262→    if (arg === '--help' || arg === '-h') {
   263→      result.showHelp = true;
   264→      continue;
   265→    }
   266→
   267→    if (arg.startsWith('--since=')) {
   268→      const dateStr = arg.split('=')[1];
   269→      const parsedDate = new Date(dateStr);
   270→
   271→      if (isNaN(parsedDate.getTime())) {
   272→        throw new Error(`Invalid date format: ${dateStr}. Use YYYY-MM-DD format.`);
   273→      }
   274→
   275→      result.sinceDate = parsedDate;
   276→    }
   277→  }
   278→
   279→  return result;
   280→}
   281→
   282→/**
   283→ * Display usage information
   284→ */
   285→function displayHelp(): void {
   286→  console.log('==============================================');
   287→  console.log('Gmail Email Fetcher CLI');
   288→  console.log('==============================================\n');
   289→  console.log('Fetch emails from Gmail API and persist to database.\n');
   290→  console.log('Usage:');
   291→  console.log('  npm run fetch:emails                        # Fetch since last DB timestamp');
   292→  console.log('  npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date');
   293→  console.log('  npm run fetch:emails -- --help              # Show this help\n');
   294→  console.log('Requirements:');
   295→  console.log('  - Gmail OAuth2 credentials (run `npm run authorize:gmail` first)');
   296→  console.log('  - Valid gmail-tokens.json file in current directory');
   297→  console.log('  - Database connection configured (see ENVIRONMENT.md)\n');
   298→}
   299→
   300→/**
   301→ * Format duration in human-readable format
   302→ */
   303→function formatDuration(ms: number): string {
   304→  if (ms < 1000) return `${ms}ms`;
   305→  if (ms < 60000) return `${(ms / 1000).toFixed(2)}s`;
   306→  return `${(ms / 60000).toFixed(2)}m`;
   307→}
   308→
   309→/**
   310→ * Load Gmail tokens from file
   311→ */
   312→function loadTokens(tokensPath: string): OAuth2Tokens {
   313→  try {
   314→    const tokensJson = fs.readFileSync(tokensPath, 'utf-8');
   315→    return JSON.parse(tokensJson) as OAuth2Tokens;
   316→  } catch (error) {
   317→    throw new Error(
   318→      `Failed to load tokens from ${tokensPath}: ${error instanceof Error ? error.message : String(error)}\n` +
   319→        'Run `npm run authorize:gmail` to obtain tokens.'
   320→    );
   321→  }
   322→}
   323→
   324→/**
   325→ * CLI entry point for fetch-emails command
   326→ *
   327→ * Parses command-line arguments and executes fetchAndPersistEmails.
   328→ * Handles authentication, logging, and error reporting.
   329→ *
   330→ * @example
   331→ * ```bash
   332→ * npm run fetch:emails                        # Fetch since last DB timestamp
   333→ * npm run fetch:emails -- --since=2024-01-01  # Fetch since custom date
   334→ * ```
   335→ */
   336→export async function main(): Promise<void> {
   337→  // Load environment variables
   338→  loadEnvironment();
   339→
   340→  try {
   341→    // Parse command-line arguments
   342→    const { sinceDate, showHelp } = parseArguments();
   343→
   344→    if (showHelp) {
   345→      displayHelp();
   346→      return;
   347→    }
   348→
   349→    console.log('==============================================');
   350→    console.log('Gmail Email Fetcher');
   351→    console.log('==============================================\n');
   352→
   353→    // Step 1: Check environment variables
   354→    console.log('Step 1: Checking Environment Configuration\n');
   355→
   356→    const clientId = process.env.GMAIL_CLIENT_ID;
   357→    const clientSecret = process.env.GMAIL_CLIENT_SECRET;
   358→    const redirectUri = process.env.GMAIL_REDIRECT_URI;
   359→
   360→    if (!clientId || !clientSecret || !redirectUri) {
   361→      console.error('❌ Error: Missing Gmail OAuth2 credentials in environment variables.\n');
   362→      console.error('Please set the following in your .env file:');
   363→      console.error('  - GMAIL_CLIENT_ID');
   364→      console.error('  - GMAIL_CLIENT_SECRET');
   365→      console.error('  - GMAIL_REDIRECT_URI\n');
   366→      console.error('See ENVIRONMENT.md for setup instructions.');
   367→      process.exit(1);
   368→    }
   369→
   370→    console.log('✅ Environment configured\n');
   371→
   372→    // Step 2: Load Gmail tokens
   373→    console.log('Step 2: Loading Gmail Tokens\n');
   374→
   375→    const tokensPath = path.join(process.cwd(), 'gmail-tokens.json');
   376→    let tokens: OAuth2Tokens;
   377→
   378→    try {
   379→      tokens = loadTokens(tokensPath);
   380→      console.log(`✅ Tokens loaded from: ${tokensPath}\n`);
   381→    } catch (error) {
   382→      console.error(`❌ ${error instanceof Error ? error.message : String(error)}`);
   383→      process.exit(1);
   384→    }
   385→
   386→    // Step 3: Initialize Gmail client and verify authentication
   387→    console.log('Step 3: Initializing Gmail Client\n');
   388→
   389→    const gmailClient = new GmailClient({
   390→      clientId,
   391→      clientSecret,
   392→      redirectUri,
   393→    });
   394→
   395→    await gmailClient.setTokens(tokens);
   396→
   397→    const authStatus = await gmailClient.getAuthStatus();
   398→    if (!authStatus.authenticated || !authStatus.tokenValid) {
   399→      console.error('❌ Error: Gmail authentication failed.\n');
   400→      console.error('Tokens may be expired or invalid. Run `npm run authorize:gmail` to obtain new tokens.');
   401→      process.exit(1);
   402→    }
   403→
   404→    console.log('✅ Gmail client authenticated\n');
   405→
   406→    // Step 4: Initialize email fetcher and repository
   407→    console.log('Step 4: Initializing Services\n');
   408→
   409→    const emailFetcher = new EmailFetcher(gmailClient);
   410→    const repository = new EmailRepository();
   411→
   412→    console.log('✅ Services initialized\n');
   413→
   414→    // Step 5: Fetch and persist emails
   415→    console.log('Step 5: Fetching Emails\n');
   416→
   417→    if (sinceDate) {
   418→      console.log(`Fetching emails since: ${sinceDate.toISOString()}`);
   419→    } else {
   420→      console.log('Fetching emails since last database timestamp (incremental fetch)');
   421→    }
   422→
   423→    console.log('This may take a moment...\n');
   424→
   425→    const result = await fetchAndPersistEmails({
   426→      gmailClient,
   427→      emailFetcher,
   428→      repository,
   429→      sinceDate,
   430→    });
   431→
   432→    // Step 6: Display results
   433→    console.log('Step 6: Results\n');
   434→    console.log('─────────────────────────────────────────────');
   435→
   436→    if (result.success) {
   437→      console.log('✅ Fetch operation completed successfully!\n');
   438→      console.log(`📊 Summary:`);
   439→      console.log(`   New emails fetched: ${result.fetchedCount}`);
   440→      console.log(`   Total messages persisted: ${result.persistedCount}`);
   441→      console.log(`   Threads affected: ${result.threadsAffected}`);
   442→
   443→      const updatedMessages = result.persistedCount - result.fetchedCount;
   444→      if (updatedMessages > 0) {
   445→        console.log(`   Updated messages: ${updatedMessages} (label sync from threads)`);
   446→      }
   447→
   448→      console.log(
   449→        `   Since timestamp: ${result.sinceTimestamp ? result.sinceTimestamp.toISOString() : 'N/A (first fetch)'}`
   450→      );
   451→      console.log(`   Duration: ${formatDuration(result.durationMs)}`);
   452→
   453→      if (result.fetchedCount === 0) {
   454→        console.log('\n💡 No new emails found since last fetch.');
   455→      }
   456→    } else {
   457→      console.log('⚠️  Fetch operation completed with errors:\n');
   458→      console.log(`📊 Summary:`);
   459→      console.log(`   New emails fetched: ${result.fetchedCount}`);
   460→      console.log(`   Total messages persisted: ${result.persistedCount}`);
   461→      console.log(`   Threads affected: ${result.threadsAffected}`);
   462→      console.log(`   Errors: ${result.errors.length}`);
   463→      console.log(`   Duration: ${formatDuration(result.durationMs)}\n`);
   464→
   465→      console.log('❌ Errors encountered:');
   466→      result.errors.forEach((error, index) => {
   467→        console.log(`   ${index + 1}. [${error.type}] ${error.message}`);
   468→      });
   469→
   470→      process.exit(1);
   471→    }
   472→
   473→    console.log('─────────────────────────────────────────────\n');
   474→
   475→    console.log('Next steps:');
   476→    console.log('  - Process emails: npm run process:gmail');
   477→    console.log('  - Generate digests: npm run generate:digests\n');
   478→
   479→    // Cleanup
   480→    await repository.close();
   481→
   482→    console.log('==============================================');
   483→    console.log('Fetch Complete! 🎉');
   484→    console.log('==============================================\n');
   485→  } catch (error) {
   486→    console.error('\n❌ Fatal error during email fetching:');
   487→    console.error(error instanceof Error ? error.message : String(error));
   488→
   489→    if (error instanceof Error && error.stack) {
   490→      console.error('\nStack trace:');
   491→      console.error(error.stack);
   492→    }
   493→
   494→    console.error('\nCommon issues:');
   495→    console.error('  - Gmail tokens expired (run `npm run authorize:gmail`)');
   496→    console.error('  - Database connection failed (check ENVIRONMENT.md)');
   497→    console.error('  - Network connectivity issues');
   498→    console.error('  - Invalid --since date format (use YYYY-MM-DD)\n');
   499→
   500→    process.exit(1);
   501→  }
   502→}
   503→
   504→// Run CLI if executed directly
   505→if (require.main === module) {
   506→  main()
   507→    .then(() => process.exit(0))
   508→    .catch((error) => {
   509→      console.error('Fatal error:', error);
   510→      process.exit(1);
   511→    });
   512→}
