   */
  onTokensRefreshed?: TokenRefreshCallback;
}

/**
 * Gmail API client with OAuth2 authentication and rate limiting support
 *
 * Handles OAuth2 authentication flows, automatic token refresh, and provides
 * robust error handling with retry logic for rate limit errors.
 *
 * **Automatic Token Refresh**: When an access token expires, the client
 * automatically refreshes it using the refresh token. If you provide an
 * `onTokensRefreshed` callback, you can persist the new tokens automatically.
 *
 * @example
 * ```typescript
 * // With automatic token persistence
 * const client = new GmailClient({
 *   clientId: 'your-client-id',
 *   clientSecret: 'your-client-secret',
 *   redirectUri: 'http://localhost:3000/oauth2callback',
 *   onTokensRefreshed: (tokens) => {
 *     fs.writeFileSync('tokens.json', JSON.stringify(tokens, null, 2));
 *   }
 * });
 *
 * // Set tokens and use the API - refresh happens automatically!
 * await client.setTokens(loadedTokens);
 * const profile = await client.getUserProfile(); // Auto-refreshes if expired
 * ```
 */
export class GmailClient {
  private readonly auth: OAuth2Client;
  private readonly gmail: gmail_v1.Gmail;
  private readonly onTokensRefreshed?: TokenRefreshCallback;
  private readonly scopes = [
    'https://www.googleapis.com/auth/gmail.readonly',
    'https://www.googleapis.com/auth/gmail.modify',
    'https://www.googleapis.com/auth/gmail.labels',
  ];

  /**
   * Creates a new Gmail API client
   *
   * @param options - OAuth2 credentials and optional callbacks (defaults to environment variables)
   * @throws Error if credentials are not provided and environment variables are not set
   */
  constructor(options?: OAuth2Credentials | GmailClientOptions) {
    // Load credentials from environment if not provided
    const creds = options || this.loadCredentialsFromEnv();

    // Validate required fields
    if (!creds.clientId || !creds.clientSecret || !creds.redirectUri) {
      throw new Error(
        'Gmail OAuth2 credentials not provided. Set GMAIL_CLIENT_ID, GMAIL_CLIENT_SECRET, and GMAIL_REDIRECT_URI environment variables or pass credentials to constructor.'
      );
    }

    // Store callback if provided
    if ('onTokensRefreshed' in creds) {
      this.onTokensRefreshed = creds.onTokensRefreshed;
    }

    // Initialize OAuth2 client
    this.auth = new google.auth.OAuth2(creds.clientId, creds.clientSecret, creds.redirectUri);

    // Listen for automatic token refresh events from googleapis OAuth2Client
    this.auth.on('tokens', (tokens) => {
      if (this.onTokensRefreshed) {
        void this.onTokensRefreshed(tokens as OAuth2Tokens);
      }
    });

    // Initialize Gmail API
    this.gmail = google.gmail({ version: 'v1', auth: this.auth });
  }

