/**
 * Gmail API Client with OAuth2 Authentication
 *
 * Provides secure Gmail API access with authentication, token management,
 * rate limiting, and error handling capabilities.
 *
 * @packageDocumentation
 */

import { gmail_v1, google } from 'googleapis';
import { OAuth2Client } from 'google-auth-library';

/**
 * OAuth2 credentials for Gmail API authentication
 */
export interface OAuth2Credentials {
  /**
   * OAuth2 client ID from Google Cloud Console
   */
  clientId: string;

  /**
   * OAuth2 client secret from Google Cloud Console
   */
  clientSecret: string;

  /**
   * OAuth2 redirect URI for authorization callback
   */
  redirectUri: string;
}

/**
 * OAuth2 token set returned from Google
 */
export interface OAuth2Tokens {
  /**
   * Access token for API requests
   */
  access_token: string | null | undefined;

  /**
   * Refresh token for obtaining new access tokens
   */
  refresh_token?: string | null;

  /**
   * Token expiration timestamp (milliseconds since epoch)
   */
  expiry_date?: number | null;

  /**
   * Token type (usually "Bearer")
   */
  token_type?: string;

  /**
   * Granted scopes
   */
  scope?: string;
}

/**
 * Gmail authentication status information
 */
export interface AuthStatus {
  /**
   * Whether OAuth2 credentials are configured
   */
  authenticated: boolean;

  /**
   * Whether the access token is valid and not expired
   */
  tokenValid: boolean;

  /**
   * Authenticated user's email address
   */
  userEmail?: string;

  /**
   * Token expiration timestamp
   */
  tokenExpiresAt?: Date;

  /**
   * Granted OAuth2 scopes
   */
  scopes?: string[];

  /**
   * Timestamp when status was checked
   */
  lastChecked: Date;
}

/**
 * Options for Gmail API requests
 */
export interface GmailRequestOptions {
  /**
   * Whether to retry on rate limit errors (429)
   * @default false
   */
  retryOnRateLimit?: boolean;

  /**
   * Maximum number of retry attempts
   * @default 3
   */
  maxRetries?: number;

  /**
   * Base delay in milliseconds between retries
   * @default 1000
   */
  retryDelayMs?: number;
}

/**
 * Gmail API client with OAuth2 authentication and rate limiting support
 *
 * Handles OAuth2 authentication flows, token management, and provides
 * robust error handling with retry logic for rate limit errors.
 *
 * @example
 * ```typescript
 * // Initialize with environment variables
 * const client = new GmailClient();
 *
 * // Or with explicit credentials
 * const client = new GmailClient({
 *   clientId: 'your-client-id',
 *   clientSecret: 'your-client-secret',
 *   redirectUri: 'http://localhost:3000/oauth2callback'
 * });
 *
 * // Set tokens after OAuth2 flow
 * await client.setTokens(tokens);
 *
 * // Fetch user profile
 * const profile = await client.getUserProfile();
 * ```
 */
export class GmailClient {
  private readonly auth: OAuth2Client;
  private readonly gmail: gmail_v1.Gmail;
  private readonly scopes = [
    'https://www.googleapis.com/auth/gmail.readonly',
    'https://www.googleapis.com/auth/gmail.modify',
    'https://www.googleapis.com/auth/gmail.labels',
  ];

  /**
   * Creates a new Gmail API client
   *
   * @param credentials - OAuth2 credentials (optional, defaults to environment variables)
   * @throws Error if credentials are not provided and environment variables are not set
   */
  constructor(credentials?: OAuth2Credentials) {
    // Load credentials from environment if not provided
    const creds = credentials || this.loadCredentialsFromEnv();

    // Validate required fields
    if (!creds.clientId || !creds.clientSecret || !creds.redirectUri) {
      throw new Error(
        'Gmail OAuth2 credentials not provided. Set GMAIL_CLIENT_ID, GMAIL_CLIENT_SECRET, and GMAIL_REDIRECT_URI environment variables or pass credentials to constructor.'
      );
    }

    // Initialize OAuth2 client
    this.auth = new google.auth.OAuth2(creds.clientId, creds.clientSecret, creds.redirectUri);

    // Initialize Gmail API
    this.gmail = google.gmail({ version: 'v1', auth: this.auth });
  }

  /**
   * Load OAuth2 credentials from environment variables
   *
   * @returns OAuth2 credentials from environment
   * @private
   */
  private loadCredentialsFromEnv(): OAuth2Credentials {
    return {
      clientId: process.env.GMAIL_CLIENT_ID || '',
      clientSecret: process.env.GMAIL_CLIENT_SECRET || '',
      redirectUri: process.env.GMAIL_REDIRECT_URI || '',
    };
  }

  /**
   * Set OAuth2 tokens for authenticated requests
   *
   * @param tokens - OAuth2 token set from Google authorization
   */
  async setTokens(tokens: OAuth2Tokens): Promise<void> {
    this.auth.setCredentials(tokens);
  }

  /**
   * Generate OAuth2 authorization URL
   *
   * Users should be redirected to this URL to grant access to their Gmail account.
   * After authorization, Google will redirect to the configured redirect URI with
   * an authorization code.
   *
   * @returns Authorization URL for user consent
   */
  getAuthorizationUrl(): string {
    return this.auth.generateAuthUrl({
      access_type: 'offline',
      scope: this.scopes,
      prompt: 'consent', // Force consent to get refresh token
    });
  }

  /**
   * Exchange authorization code for OAuth2 tokens
   *
   * After user grants access, Google redirects with an authorization code.
   * Exchange this code for access and refresh tokens.
   *
   * @param code - Authorization code from OAuth2 callback
   * @returns OAuth2 token set
   * @throws Error if code exchange fails
   */
  async exchangeCodeForTokens(code: string): Promise<OAuth2Tokens> {
    const { tokens } = await this.auth.getToken(code);
    const oauthTokens = tokens as OAuth2Tokens;
    await this.setTokens(oauthTokens);
    return oauthTokens;
  }

  /**
   * Refresh expired access token using refresh token
   *
   * @returns New OAuth2 token set
   * @throws Error if refresh fails or refresh token is not set
   */
  async refreshTokens(): Promise<OAuth2Tokens> {
    const { credentials } = await this.auth.refreshAccessToken();
    const oauthTokens = credentials as OAuth2Tokens;
    await this.setTokens(oauthTokens);
    return oauthTokens;
  }

  /**
   * Get authenticated user's Gmail profile
   *
   * @param options - Request options for rate limiting and retries
   * @returns User profile information
   * @throws Error if not authenticated or API request fails
   */
  async getUserProfile(options?: GmailRequestOptions): Promise<gmail_v1.Schema$Profile> {
    return this.executeWithRetry(async () => {
      const response = await this.gmail.users.getProfile({ userId: 'me' });
      return response.data;
    }, options);
  }

  /**
   * Get current authentication status
   *
   * Checks whether OAuth2 tokens are set, valid, and not expired.
   * Optionally fetches user profile to verify token validity.
   *
   * @returns Authentication status information
   */
  async getAuthStatus(): Promise<AuthStatus> {
    const credentials = this.auth.credentials;
    const now = new Date();

    // Check if tokens are set
    if (!credentials.access_token) {
      return {
        authenticated: false,
        tokenValid: false,
        lastChecked: now,
      };
    }

    // Check if token is expired
    const tokenValid = credentials.expiry_date ? credentials.expiry_date > Date.now() : false;

    // Try to fetch user profile to verify token validity
    let userEmail: string | undefined;
    try {
      const profile = await this.getUserProfile();
      userEmail = profile.emailAddress || undefined;
    } catch {
      // Token might be invalid even if not expired
      return {
        authenticated: true,
        tokenValid: false,
        lastChecked: now,
      };
    }

    return {
      authenticated: true,
      tokenValid,
      userEmail,
      tokenExpiresAt: credentials.expiry_date ? new Date(credentials.expiry_date) : undefined,
      scopes: credentials.scope?.split(' ') || this.scopes,
      lastChecked: now,
    };
  }

  /**
   * Execute Gmail API request with retry logic for rate limiting
   *
   * Public method to allow custom Gmail API operations with built-in retry logic.
   * Automatically retries on rate limit errors (429) with exponential backoff.
   *
   * @param operation - Async operation to execute
   * @param options - Retry options
   * @returns Operation result
   * @throws Error if all retry attempts fail
   * @public
   */
  async executeWithRetry<T>(operation: () => Promise<T>, options?: GmailRequestOptions): Promise<T> {
    const maxRetries = options?.maxRetries ?? 3;
    const retryDelayMs = options?.retryDelayMs ?? 1000;
    const retryOnRateLimit = options?.retryOnRateLimit ?? false;

    let lastError: Error | undefined;
    let attempt = 0;

    while (attempt <= maxRetries) {
      try {
        return await operation();
      } catch (error) {
        lastError = error as Error;
        attempt++;

        const apiError = error as { code?: number; errors?: Array<{ domain?: string; reason?: string }> };

        // Check if this is a rate limit error
        const isRateLimitError =
          apiError.code === 429 ||
          apiError.errors?.some((e) => e.domain === 'usageLimits' && e.reason === 'rateLimitExceeded');

        // Only retry on rate limit errors if enabled
        if (!retryOnRateLimit || !isRateLimitError) {
          throw error;
        }

        // Don't retry if we've exhausted attempts
        if (attempt > maxRetries) {
          throw error;
        }

        // Exponential backoff with jitter (reduced for testing)
        const delay = retryDelayMs * Math.pow(2, attempt - 1) + Math.random() * 100;
        await this.sleep(delay);
      }
    }

    throw lastError;
  }

  /**
   * List Gmail messages with retry logic
   *
   * Wraps Gmail API's users.messages.list with automatic retry on rate limits.
   *
   * @param params - List parameters (query, labelIds, maxResults, pageToken)
   * @param options - Retry options
   * @returns List response with messages and pagination info
   * @throws Error if API request fails after retries
   */
  async listMessages(
    params: gmail_v1.Params$Resource$Users$Messages$List,
    options?: GmailRequestOptions
  ): Promise<gmail_v1.Schema$ListMessagesResponse> {
    return this.executeWithRetry(async () => {
      const response = await this.gmail.users.messages.list({
        userId: 'me',
        ...params,
      });
      return response.data;
    }, options);
  }

  /**
   * Get single Gmail message with retry logic
   *
   * Wraps Gmail API's users.messages.get with automatic retry on rate limits.
   *
   * @param messageId - Gmail message ID
   * @param format - Message format (full, minimal, metadata, raw)
   * @param options - Retry options
   * @returns Gmail message
   * @throws Error if API request fails after retries
   */
  async getMessage(
    messageId: string,
    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full',
    options?: GmailRequestOptions
  ): Promise<gmail_v1.Schema$Message> {
    return this.executeWithRetry(async () => {
      const response = await this.gmail.users.messages.get({
        userId: 'me',
        id: messageId,
        format,
      });
      return response.data;
    }, options);
  }

  /**
   * Get multiple Gmail messages in parallel with retry logic
   *
   * Fetches messages concurrently using Promise.all, each with retry support.
   * For more efficient batching, use batchGetMessages() instead.
   *
   * @param messageIds - Array of Gmail message IDs
   * @param format - Message format (full, minimal, metadata, raw)
   * @param options - Retry options applied to each individual request
   * @returns Array of Gmail messages in same order as input IDs
   * @throws Error if any request fails after retries
   */
  async getMessages(
    messageIds: string[],
    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full',
    options?: GmailRequestOptions
  ): Promise<gmail_v1.Schema$Message[]> {
    const promises = messageIds.map((id) => this.getMessage(id, format, options));
    return Promise.all(promises);
  }

  /**
   * Get multiple Gmail messages with error resilience
   *
   * Fetches messages in parallel using individual API calls with Promise.all.
   * Each message is fetched independently with its own error handling, allowing
   * successful fetches to complete even if some messages fail.
   *
   * **Implementation Note**: This method uses parallel individual requests rather
   * than Gmail's batch API (`/batch/gmail/v1` endpoint) for the following reasons:
   *
   * 1. **Simplicity**: Batch API requires complex multipart/mixed HTTP request construction
   * 2. **Library Support**: googleapis v129 lacks clear documentation/examples for Gmail batch requests
   * 3. **Error Handling**: Individual requests provide better granular error handling per message
   * 4. **HTTP/2**: Modern googleapis library uses HTTP/2 multiplexing, providing similar performance
   * 5. **Maintainability**: Promise.all approach is easier to debug, test, and maintain
   *
   * The parallel approach with HTTP/2 achieves comparable performance to batch requests
   * while maintaining code simplicity and robust error handling.
   *
   * @param messageIds - Array of Gmail message IDs
   * @param format - Message format (full, minimal, metadata, raw)
   * @param options - Retry options applied to each request
   * @returns Object mapping message IDs to messages or errors
   */
  async batchGetMessages(
    messageIds: string[],
    format: 'full' | 'minimal' | 'metadata' | 'raw' = 'full',
    options?: GmailRequestOptions
  ): Promise<Record<string, gmail_v1.Schema$Message | Error>> {
    const results: Record<string, gmail_v1.Schema$Message | Error> = {};

    const promises = messageIds.map(async (id) => {
      try {
        const message = await this.getMessage(id, format, options);
        results[id] = message;
      } catch (error) {
        results[id] = error as Error;
      }
    });

    await Promise.all(promises);
    return results;
  }

  /**
   * Get single Gmail thread with all messages
   *
   * Wraps Gmail API's users.threads.get with automatic retry on rate limits.
   * Returns a thread containing all messages with their complete details.
   *
   * @param threadId - Gmail thread ID
   * @param format - Thread format (full, metadata, minimal)
   *   - full: Returns complete message data with body content for all messages
   *   - metadata: Returns only message IDs, labels, and headers for all messages
   *   - minimal: Returns only message IDs and labels for all messages
   * @param options - Retry options
   * @returns Gmail thread with messages array
   * @throws Error if API request fails after retries
   *
   * @example
   * ```typescript
   * // Get thread with all message details
   * const thread = await client.getThread('thread-id-123', 'full');
   * console.log(`Thread has ${thread.messages?.length} messages`);
   * thread.messages?.forEach(msg => {
   *   console.log(`  - ${msg.id}: ${msg.labelIds}`);
   * });
   * ```
   */
  async getThread(
    threadId: string,
    format: 'full' | 'metadata' | 'minimal' = 'full',
    options?: GmailRequestOptions
  ): Promise<gmail_v1.Schema$Thread> {
    return this.executeWithRetry(async () => {
      const response = await this.gmail.users.threads.get({
        userId: 'me',
        id: threadId,
        format,
      });
      return response.data;
    }, options);
  }

  /**
   * List all Gmail labels for the authenticated user
   *
   * Wraps Gmail API's users.labels.list with automatic retry on rate limits.
   *
   * @param options - Retry options
   * @returns List of Gmail labels
   * @throws Error if API request fails after retries
   */
  async listLabels(options?: GmailRequestOptions): Promise<gmail_v1.Schema$Label[]> {
    return this.executeWithRetry(async () => {
      const response = await this.gmail.users.labels.list({
        userId: 'me',
      });
      return response.data.labels || [];
    }, options);
  }

  /**
   * Get a specific Gmail label by ID
   *
   * Wraps Gmail API's users.labels.get with automatic retry on rate limits.
   *
   * @param labelId - Gmail label ID
   * @param options - Retry options
   * @returns Gmail label
   * @throws Error if API request fails after retries
   */
  async getLabel(labelId: string, options?: GmailRequestOptions): Promise<gmail_v1.Schema$Label> {
    return this.executeWithRetry(async () => {
      const response = await this.gmail.users.labels.get({
        userId: 'me',
        id: labelId,
      });
      return response.data;
    }, options);
  }

  /**
   * Sleep for specified duration
   *
   * @param ms - Milliseconds to sleep
   * @private
   */
  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  /**
   * Dispose resources and cleanup
   *
   * Currently a no-op but provided for future resource cleanup needs.
   */
  async dispose(): Promise<void> {
    // No cleanup needed currently, but method exists for future use
  }

  /**
   * Get underlying Gmail API instance for advanced usage
   *
   * @returns Gmail API v1 instance
   */
  getGmailApi(): gmail_v1.Gmail {
    return this.gmail;
  }

  /**
   * Get underlying OAuth2 client for advanced auth operations
   *
   * @returns OAuth2Client instance
   */
  getOAuth2Client(): OAuth2Client {
    return this.auth;
  }
}

