    if ('onTokensRefreshed' in creds && typeof creds.onTokensRefreshed === 'function') {
      this.onTokensRefreshed = creds.onTokensRefreshed;
    }

    // Initialize OAuth2 client
    this.auth = new google.auth.OAuth2(creds.clientId, creds.clientSecret, creds.redirectUri);

    // Listen for automatic token refresh events from googleapis OAuth2Client
    this.auth.on('tokens', (tokens) => {
      if (this.onTokensRefreshed) {
        void this.onTokensRefreshed(tokens as OAuth2Tokens);
